const b = $json.body ?? $json;


const category = (b.category ?? "").toString().trim();
if (!category) throw new Error("Missing category");


const writingStyleMap = {
  "Journalistic": "journalistic",
  "Academic": "academic",
  "Executive": "executive",
  "journalistic": "journalistic",
  "academic": "academic",
  "executive": "executive",
};

const outputFormatMap = {
  "Paragraph": "paragraph",
  "Bullet Point": "bullet_points",
  "Bullet Points": "bullet_points",
  "TLDR": "tldr",
  "Sections": "sections",
  "paragraph": "paragraph",
  "bullet_points": "bullet_points",
  "tldr": "tldr",
  "sections": "sections",
};

const writing_style = writingStyleMap[b.writing_style] ?? "journalistic";
const output_format = outputFormatMap[b.output_format] ?? "bullet_points";
const institutional = (typeof b.institutional === "boolean") ? b.institutional : false;

// 可选：language / size（这里 size 固定查最新 1 条，你也可让前端传 size）
const language = (b.language ?? "en").toString().trim() || "en";
const size = (typeof b.size === "number" && b.size > 0) ? b.size : 1;

return [{
  json: {
    category,
    language,
    size,
    params: { writing_style, output_format, institutional }
  }
}];

const { category, size, language, params } = $json;

const os_query = {
  size, 
  _source: ["cluster_id", "summary", "processed_at", "category", "language"],
  query: {
    bool: {
      must: [
        { term: { "category": category } },
        { exists: { field: "summary" } }
      ]
    }
  },
  sort: [{ processed_at: { order: "desc" } }]
};



return [{
  json: {
    category,
    language,
    params,
    index: "cluster_summaries",
    os_query
  }
}];

const r = $json;
const hits = r?.hits?.hits ?? r?.body?.hits?.hits ?? r?.result?.hits?.hits ?? [];

if (!hits.length) {
  return [{
    json: {
      error: "No cluster summary found for this category",
      found: 0
    }
  }];
}

const src = hits[0]._source ?? hits[0].source ?? hits[0];

const params = $node["Build cluster search query"].json.params;
const category = $node["Build cluster search query"].json.category;
const language = $node["Build cluster search query"].json.language;


return [{
  json: {
    category,
    language,
    params,
    cluster_id: src.cluster_id,
    summary: src.summary,
    processed_at: src.processed_at ?? null
  }
}];
;

const j = $json;
const p = j.params ?? {};

const writing_style = p.writing_style ?? "journalistic";
const output_format = p.output_format ?? "bullet_points";
const institutional = p.institutional ?? false;

const cluster_id = j.cluster_id ?? "unknown";


const request_id = `style_${new Date().toISOString()}_${cluster_id}`;


const summary = (j.summary ?? "").toString().trim();
if (!summary) throw new Error("Missing summary for styling");

return [{
  json: {
    ...j,                 
    request_id,
    style_request: {
      request_id,
      summary,
      writing_style,
      output_format,
      institutional
    }
  }
}];

return [{
  json: {
    batches_processed: 0,
    source_clusters: 0,
    final_summary: "",
    message: $json.error ?? "error",
    all_clusters: [],
    individual_summaries: []
  }
}];

// FINAL n8n CODE NODE - For /summary_style endpoint on port 8001

const incomingBody = $input.item.json.body;

const summary = incomingBody.summary || "";
const requestId = incomingBody.request_id || "unknown";
const writingStyle = incomingBody.writing_style;
const outputFormat = incomingBody.output_format;
const editorialTone = incomingBody.editorial_tone;

const styleMapping = {
  "Journalistic": "journalistic",
  "Academic": "academic",
  "Executive": "executive",
  "LinkedIn": "linkedin"
};

const formatMapping = {
  "Paragraph": "paragraph",
  "Bullet Point": "bullet_points",
  "TL;DR": "tldr",
  "Sections": "sections"
};

const toneMapping = {
  "Institutional": true,
  "Neutral": false,
  "Default": false
};

// Map the values
let mappedWritingStyle = styleMapping[writingStyle] || writingStyle;
let mappedOutputFormat = formatMapping[outputFormat] || outputFormat;
let mappedInstitutional = toneMapping[editorialTone] !== undefined ? toneMapping[editorialTone] : false;

// Clean up invalid values
if (!mappedWritingStyle || mappedWritingStyle === "Default" || mappedWritingStyle === "null") {
  mappedWritingStyle = null;
}
if (!mappedOutputFormat || mappedOutputFormat === "Default" || mappedOutputFormat === "null") {
  mappedOutputFormat = null;
}

// Build request with required fields
const transformedRequest = {
  request_id: requestId,
  summary: summary,
  institutional: mappedInstitutional,
};

// Only add optional fields if they have valid values
if (mappedWritingStyle) {
  transformedRequest.writing_style = mappedWritingStyle;
}

if (mappedOutputFormat) {
  transformedRequest.output_format = mappedOutputFormat;
}

console.log("Transformed request:", JSON.stringify(transformedRequest, null, 2));

return {
  json: transformedRequest
};

const response = $input.item.json;
const result = Array.isArray(response) ? response[0] : response;

// Return just the data fields directly
return {
  styled_summary: result.styled_summary || "",
  request_id: result.request_id || "unknown",
  writing_style: result.writing_style,
  output_format: result.output_format,
  institutional: result.institutional || false,
  processed_at: result.processed_at || new Date().toISOString()
};
